/* Lightweight local HTML sanitizer for the static portal. Exposes DOMPurify.sanitize(html). */
(function () {
  const allowedTags = new Set(["A", "BLOCKQUOTE", "BR", "CODE", "DIV", "EM", "H1", "H2", "H3", "H4", "H5", "H6", "HR", "LI", "OL", "P", "PRE", "SPAN", "STRONG", "TABLE", "TBODY", "TD", "TH", "THEAD", "TR", "UL"]);
  const allowedAttrs = new Set(["href", "title", "class", "id", "target", "rel"]);

  function safeHref(value) {
    const href = String(value || "").trim();
    return href.startsWith("#") || href.startsWith("./") || href.startsWith("../") || href.startsWith("docs/") || href.startsWith("mailto:") || href.startsWith("https://") || href.startsWith("http://");
  }

  function sanitize(html) {
    const template = document.createElement("template");
    template.innerHTML = String(html || "");

    template.content.querySelectorAll("*").forEach((node) => {
      if (!allowedTags.has(node.tagName)) {
        node.replaceWith(...Array.from(node.childNodes));
        return;
      }

      Array.from(node.attributes).forEach((attribute) => {
        const name = attribute.name.toLowerCase();
        if (name.startsWith("on") || !allowedAttrs.has(name)) {
          node.removeAttribute(attribute.name);
          return;
        }
        if (name === "href" && !safeHref(attribute.value)) node.removeAttribute(attribute.name);
      });

      if (node.tagName === "A") {
        node.setAttribute("rel", "noreferrer");
        if (/^https?:\/\//.test(node.getAttribute("href") || "")) node.setAttribute("target", "_blank");
      }
    });

    return template.innerHTML;
  }

  window.DOMPurify = { sanitize };
}());
